('01000000-0000-4000-8000-0000000003af', 'ui_about_page_lead', '*', '{"label":{"tr":"GoldMoodAstro, doğrulanmış danışmanlarla kişisel farkındalığı ve ruhsal rehberliği erişilebilir hale getirir.","en":"GoldMoodAstro makes personal awareness and spiritual guidance accessible through verified consultants.","de":"GoldMoodAstro macht Selbstwahrnehmung und spirituelle Begleitung durch geprüfte Berater zugänglich."}}'),
('01000000-0000-4000-8000-0000000003b0', 'ui_about_page_description', '*', '{"label":{"tr":"Astroloji, tarot, numeroloji ve mood danışmanlığı alanlarında güvenli randevu, ödeme ve canlı görüşme deneyimi sunuyoruz.","en":"We offer secure booking, payment and live session experiences across astrology, tarot, numerology and mood consulting.","de":"Wir bieten sichere Termin-, Zahlungs- und Live-Sitzungen für Astrologie, Tarot, Numerologie und Mood-Beratung."}}'),
